{"command": "create", "path": "/tmp/remove_port_from_odb.tcl", "file_text": "# OpenROAD TCL script to remove unplaced ports from ODB and write clean ODB

set odb_in "/workspace/nc-project-20260529-210526/mspm33c321a_derivative_mcu/openlane/mspm33c321a_derivative_mcu_wrapper/runs/pnr_run_v2/44-odb-applydeftemplate/mspm33c321a_derivative_mcu_wrapper.odb"
set odb_out "/workspace/nc-project-20260529-210526/mspm33c321a_derivative_mcu/openlane/mspm33c321a_derivative_mcu_wrapper/runs/pnr_run_v2/44-odb-applydeftemplate/mspm33c321a_derivative_mcu_wrapper.odb"

read_db $odb_in

set db [ord::get_db]
set chip [$db getChip]
set block [$chip getBlock]

set ports_to_remove {reset_n_pad_a_esd_0_h reset_n_pad_a_noesd_h}

foreach port_name $ports_to_remove {
    set bterm [$block findBTerm $port_name]
    if {$bterm ne "NULL" && $bterm ne ""} {
        puts "Removing port: $port_name"
        odb::dbBTerm_destroy $bterm
    } else {
        puts "Port not found (already clean): $port_name"
    }
}

# Write the modified ODB
write_db $odb_out
puts "Written clean ODB to: $odb_out"
exit
"}

